mapper.select:
SELECT r.*, p.project_name, b.building_name, f.floor_name FROM elder_room r LEFT JOIN elder_floor f on f.id = r.floor_id LEFT JOIN elder_project p ON r.project_id = p.id LEFT JOIN elder_building b ON b.id = r.building_id WHERE r.del_flag = 0
AND r.project_id IN (
#{id}
)
AND r.project_id = #{data.projectId}
AND r.building_id = #{data.buildingId}
AND r.floor_id = #{data.floorId}
AND r.room_type = #{data.roomType}
AND r.room_no LIKE concat(concat('%',#{data.roomNo}),'%')
order by r.create_time desc
